import { useState } from "react";

const wishList = [];

export default function App() {
  const [wish, setWish] = useState("");
  const [items, setItem] = useState([]);

  function handleAdd(e) {
    e.preventDefault();
    if (!wish.trim()) return;

    const newItem = {
      name: wish,
      id: Date.now(),
    };
    setItem([...items, newItem]);
    setWish("");
  }

  function handleDelete(idToRemove) {
    setItem(wishList.filter((item) => item.id !== idToRemove));
  }

  return (
    <div
      style={{
        padding: "30px",
        background: "#1e1e2e",
        color: "#cdd6f4",
        minHeight: "100vh",
        fontFamily: "sans-serif",
      }}
    >
      <h2>Список Бажанок 🎁</h2>
      <form style={{ marginBottom: "20px" }} onSubmit={handleAdd}>
        <input
          type="text"
          placeholder="Що хочеш купити?"
          value={wish}
          onChange={(e) => setWish(e.target.value)}
          style={{
            padding: "10px",
            borderRadius: "5px",
            border: "none",
            marginRight: "10px",
          }}
        />

        <button
          type="submit"
          style={{
            padding: "10px 20px",
            borderRadius: "5px",
            border: "none",
            background: "#a6e3a1",
            cursor: "pointer",
            fontWeight: "bold",
          }}
        >
          Додати
        </button>
      </form>

      <ul style={{ listStyle: "none", padding: 0 }}>
